package main

import (
	"fmt"
	"sort"
)

type Student struct {
	Name  string
	Grade int
}

func main() {
	students := []Student{
		{"Ahmet", 85},
		{"Ayse", 92},
		{"Mehmet", 67},
		{"Zeynep", 78},
		{"Can", 55},
	}

	fmt.Println("Tum ogrenciler:")
	for _, s := range students {
		fmt.Println(s.Name, ":", s.Grade)
	}

	// Yeni ogrenci ekleme
	students = append(students, Student{"Elif", 88})
	fmt.Println("\nElif eklendi. Toplam ogrenci:", len(students))

	// Not güncelleme
	for i := range students {
		if students[i].Name == "Mehmet" {
			students[i].Grade = 70
			fmt.Println("\nMehmet'in notu guncellendi:", students[i].Grade)
		}
	}

	// Geçenler / kalanlar sayısı
	passing, failing := 0, 0
	for _, s := range students {
		if s.Grade >= 60 {
			passing++
		} else {
			failing++
		}
	}

	fmt.Println("\nGecen ogrenci sayisi:", passing)
	fmt.Println("Kalan ogrenci sayisi:", failing)

	// Sıralama (en yüksekten en düşüğe)
	sort.Slice(students, func(i, j int) bool {
		return students[i].Grade > students[j].Grade
	})

	fmt.Println("\nNot siralamasi (yuksekten alcaga):")
	for _, s := range students {
		fmt.Println(s.Name, ":", s.Grade)
	}

	// Ortalama
	total := 0
	for _, s := range students {
		total += s.Grade
	}
	avg := float64(total) / float64(len(students))
	fmt.Printf("\nSinif ortalamasi: %.2f\n", avg)
}
